<template>
  <el-container>
    <el-header>
      <div class="header-l">
        <a href="http://localhost" class="gotoindex">Blog Center</a>
      </div>
      <el-dropdown @command="handleCommand">
        <span class="el-dropdown-link">
          <i class="el-icon-s-custom"></i>
          {{userInfo.username}}
          <i
            class="el-icon-arrow-down el-icon--right"
            style="margin-left:5px"
          ></i>
        </span>
        <el-dropdown-menu slot="dropdown">
          <el-dropdown-item command="info">个人信息</el-dropdown-item>
          <el-dropdown-item command="pwd">修改密码</el-dropdown-item>
          <el-dropdown-item command="logout">退出系统</el-dropdown-item>
        </el-dropdown-menu>
      </el-dropdown>
    </el-header>
    <el-container>
      <!-- 菜单栏折叠-->
      <el-aside :width="isfold?'64px':'200px'">
        <div class="toggle" @click="toggle">
          <i :class="isfold?'el-icon-s-unfold':'el-icon-s-fold'"></i>
        </div>
        <!-- 菜单栏 -->
        <el-menu
          class="el-menu-vertical-demo"
          background-color="#fff"
          text-color="#333"
          unique-opened
          :collapse-transition="false"
          :collapse="isfold"
          router
          :default-active="currentMenu"
        >
          <el-menu-item index="/index" @click="handleMenuToggle">
            <template slot="title">
              <i class="el-icon-house"></i>
              <span class="module_name">首页</span>
            </template>
          </el-menu-item>
          <el-menu-item index="/users" @click="handleMenuToggle">
            <template slot="title">
              <i class="el-icon-user"></i>
              <span class="module_name">用户管理</span>
            </template>
          </el-menu-item>

          <el-submenu index="article">
            <template slot="title">
              <i class="el-icon-document-copy"></i>
              <span class="module_name">文章管理</span>
            </template>
            <el-menu-item index="/article/add" @click="handleMenuToggle">
              <template slot="title">
                <i class="el-icon-edit"></i>
                <span>写文章</span>
              </template>
            </el-menu-item>
            <el-menu-item index="/articles" @click="handleMenuToggle">
              <template slot="title">
                <i class="el-icon-s-order"></i>
                <span>文章列表</span>
              </template>
            </el-menu-item>
            <el-menu-item index="/categories" @click="handleMenuToggle">
              <template slot="title">
                <i class="el-icon-menu"></i>
                <span>文章分类</span>
              </template>
            </el-menu-item>
          </el-submenu>
          <el-submenu index="comment">
            <template slot="title">
              <i class="el-icon-chat-dot-square"></i>
              <span class="module_name">评论管理</span>
            </template>
            <el-menu-item index="/comments" @click="handleMenuToggle">
              <template slot="title">
                <i class="el-icon-s-comment"></i>
                <span>文章评论</span>
              </template>
            </el-menu-item>
            <el-menu-item index="/messages" @click="handleMenuToggle">
              <template slot="title">
                <i class="el-icon-message"></i>
                <span>留言评论</span>
              </template>
            </el-menu-item>
          </el-submenu>
          <el-menu-item index="/settings" @click="handleMenuToggle">
            <template slot="title">
              <i class="el-icon-setting"></i>
              <span class="module_name">系统设置</span>
            </template>
          </el-menu-item>
        </el-menu>
      </el-aside>
      <!-- 主内容 -->
      <el-main v-loading="isloading">
        <router-view @changeMenu="handleChangeMenu" @loading="handleLoading"></router-view>
      </el-main>
    </el-container>
    <el-dialog title="修改密码" :visible.sync="pwdDialogVisible" width="35%" @close="handlePwdClose">
      <el-form
        label-position="left"
        ref="ruleForm"
        label-width="100px"
        :model="ruleForm"
        :rules="rules"
        status-icon
      >
        <el-form-item label="原密码" >
          <el-input type="password" v-model="ruleForm.oldPass" autocomplete="off"></el-input>
        </el-form-item>
        <el-form-item label="新密码" prop="pass" >
          <el-input type="password" v-model="ruleForm.pass" autocomplete="off"></el-input>
        </el-form-item>
        <el-form-item label="确认密码" prop="checkPass" >
          <el-input type="password" v-model="ruleForm.checkPass" autocomplete="off"></el-input>
        </el-form-item>
        <div class="btns">
          <el-button type="primary" @click="handlePwdSubmit">确认修改</el-button>
          <el-button type @click="handlePwdClose">取消</el-button>
        </div>
        <div style="clear:both"></div>
      </el-form>
    </el-dialog>
    <el-dialog title="个人信息" :visible.sync="userDialogVisible" width="35%" @close="handleUserClose">
      <el-form
        label-position="left"
        ref="userForm"
        label-width="100px"
        :model="userForm"
        status-icon
      >
        <el-form-item label="uid:" required>
          <el-input v-model="userForm.uid"></el-input>
        </el-form-item>
        <el-form-item label="昵称:" required>
          <el-input v-model="userForm.username" autocomplete="off"></el-input>
        </el-form-item>
        <el-form-item label="qq:" required>
          <el-input v-model="userForm.qq" autocomplete="off"></el-input>
        </el-form-item>
        <el-form-item label="邮箱:">
          <el-input v-model="userForm.email" autocomplete="off"></el-input>
        </el-form-item>
        <el-form-item label="电话:">
          <el-input v-model="userForm.tel" autocomplete="off"></el-input>
        </el-form-item>
        <div class="btns">
          <el-button type="primary" @click="handleUserSubmit">确认</el-button>
          <el-button type @click="handleUserClose">取消</el-button>
        </div>
        <div style="clear:both"></div>
      </el-form>
    </el-dialog>
  </el-container>
</template>
<script>
export default {
  data() {
    var validatePass = (rule, value, callback) => {
      if (!value ) {
        callback(new Error("请输入密码"));
      } else {
        if (this.ruleForm.checkPass !== "") {
          this.$refs.ruleForm.validateField("checkPass");
        }
        callback();
      }
    };
    var validatePass2 = (rule, value, callback) => {
      if (!value) {
        callback(new Error("请再次输入密码"));
      } else if (value !== this.ruleForm.pass) {
        callback(new Error("两次输入密码不一致!"));
      } else {
        callback();
      }
    };
    return {
      isfold: false,
      isloading:false,
      currentMenu: "/index",
      pwdDialogVisible: false,
      userDialogVisible: false,
      userForm: {},
      ruleForm: {},
      userInfo: {},
      rules: {
        pass: [{ validator: validatePass, trigger: "blur" }],
        checkPass: [{ validator: validatePass2, trigger: "blur" }]
      }
    };
  },
  created() {
    
    this.currentMenu = window.sessionStorage.getItem("menu") || "/index";

    this.getUserInfo();
  },
  methods: {
    logout() {
      window.sessionStorage.removeItem("menu");
      this.$message.success("退出成功");
      this.$router.push("/login");
    },
    getUserInfo() {
      this.userInfo = JSON.parse(window.localStorage.getItem("user"));
    },
    handleLoading(isload){
      this.isloading=isload
    },
    handleCommand(command) {
      if (command == "info") {
        this.userForm = {
          uid: this.userInfo.uid,
          qq: this.userInfo.qq,
          username: this.userInfo.username,
          email: this.userInfo.email || "",
          tel: this.userInfo.tel || ""
        };
        this.userDialogVisible = true;
      } else if (command == "pwd") this.pwdDialogVisible = true;
      else this.logout();
    },
    toggle() {
      this.isfold = !this.isfold;
    },
    handleMenuToggle(e) {
      window.sessionStorage.setItem("menu", e.index);
      this.currentMenu = e.index;
    },
    handleChangeMenu(menu,id) {
      window.sessionStorage.setItem("menu", menu);
      this.$router.push({ path: '/article/add', query: { id: id }});
    },
    handlePwdClose() {
      this.$refs["ruleForm"].resetFields();
      this.pwdDialogVisible = false;
    },
    handleUserClose() {
      this.userDialogVisible = false;
    },
    handlePwdSubmit() {
      var that = this;
      this.$refs["ruleForm"].validate(async valid => {
        if (valid) {
          let result = await that.$http.put("/users/" + this.userInfo._id, {
            oldPass: that.ruleForm.oldPass,
            password: that.ruleForm.pass
          });
          if (result.meta.status != 200)
            return that.$message.error("修改失败," + result.meta.msg);
          else that.$message.success("修改成功");
          that.handlePwdClose();
        } else {
          that.$message.error("表单验证失败" );
          return false;
        }
      });
    },
    async handleUserSubmit() {
      let { _id } = this.userInfo;
      if (!this.userForm.uid || !this.userForm.username || !this.userForm.qq)
        return this.$message.error("请填写必填项");
      let result = await this.$http.put("/users/" + _id, this.userForm);
      if (result.meta.status != 200) this.$message.error("保存失败");
      this.$message.success("保存成功");
      window.localStorage.setItem("user", JSON.stringify(result.data));
      this.getUserInfo();
      this.userDialogVisible = false;
      this.$refs.userForm.resetFields();
    }
  }
};
</script>
<style  scoped>
.btns {
  float: right;
}
.gotoindex {
  text-decoration: none;
  color: #fff;
}
.header-l {
  width: 200px;
  text-align: center;
  background-color: rgb(6, 185, 140);
  height: 100%;
  line-height: 60px;
}
.el-container {
  height: 100%;
  color: #333;
  background-color: rgb(246, 248, 250);
}
.el-header {
  background-color: #00c292;
  display: flex;
  justify-content: space-between;
  align-items: center;
  color: #fff;
  font-size: 20px;
  padding: 0 0 !important;
}
.el-aside {
  background-color: #fff;
}
.el-menu-vertical-demo {
  border-right: none;
}
.logoutbtn {
  height: 80%;
}
.module_name {
  margin-left: 7px;
}
.toggle {
  background-color: #ccc;
  font-size: 20px;
  text-align: center;
  line-height: 37px;
}
.toggle:hover {
  cursor: pointer;
}
.el-dropdown {
  margin-right: 15px;
}
.el-dropdown-link {
  cursor: pointer;
  color: #fff;
}
</style>