<template>
  <div class="login-container">
    <div class="login-box">
      <div class="avatar">
        <img src="../assets/logo.png" alt />
      </div>
      <div>
        <el-form ref="form" class="login-form" :model="form" :rules="rules">
          <el-form-item prop="uid">
            <el-input prefix-icon="iconfont icon-user" v-model="form.uid" placeholder="请输入账号"></el-input>
          </el-form-item>
          <el-form-item prop="pwd">
            <el-input
              placeholder="请输入密码"
              v-model="form.pwd"
              prefix-icon="iconfont icon-3702mima"
              type="password"
            ></el-input>
          </el-form-item>
          <el-button type="info" class="reset-btn" @click="resetForm">重置</el-button>
          <el-button type="primary" class="login-btn" @click="loginForm">登录</el-button>
        </el-form>
      </div>
    </div>
  </div>
</template>
<script>
export default {
  data() {
    return {
      form: {
        uid: "wxh123",
        pwd: "123456"
      },
      rules: {
        uid: [
          { required: true, message: "请输入账号", trigger: "blur" },
          { min: 3, max: 15, message: "长度在 3 到 15 个字符", trigger: "blur" }
        ],
        pwd: [
          { required: true, message: "请输入密码", trigger: "blur" },
          { min: 6, max: 18, message: "长度在 6 到 18 个字符", trigger: "blur" }
        ]
      }
    };
  },
  methods: {
    loginForm: function() {
      //表单预验证
      this.$refs.form.validate(async valid => {
        if (!valid) return;
        let result = await this.$http.post("/login", {
            uid:this.form.uid,
            pwd:this.form.pwd
        });
        if (result.meta.status != 200)
           this.$message.error(result.meta.msg);
        else {
          window.localStorage.setItem('token',result.data.token)
          window.localStorage.setItem('user',JSON.stringify(result.data))
          this.$message.success('登陆成功');
          this.$router.push('/index');
        }
      });
    },
    resetForm: function() {
      this.$refs.form.resetFields();
    }
  }
};
</script>

<style scoped>
.login-container {
  position: absolute;
  left: 50%;
  top: 50%;
  transform: translate(-50%, -50%);
}
.login-box {
  position: relative;
  width: 450px;
  height: 300px;
  background-color: #fff;
  border-radius: 5px;
}
.avatar {
  border-radius: 50%;
  border: 10px solid #fff;
  width: 130px;
  height: 130px;
  position: absolute;
  left: 50%;
  transform: translate(-50%, -50%);
  background-color: #eee;
  box-shadow: 0px 0 3px 3px #ccc;
}
.avatar img {
  width: 100%;
  height: 100%;
  border-radius: 50%;
}
.login-form {
  width: 380px;
  position: absolute;
  top: 40%;
  left: 50%;
  transform: translateX(-50%);
}
.reset-btn {
  float: right;
}
.login-btn {
  float: right;
  margin-right: 10px;
}
</style>