<template>
  <div>
    <el-breadcrumb separator-class="el-icon-arrow-right">
      <el-breadcrumb-item :to="{ path: '/' }">首页</el-breadcrumb-item>
      <el-breadcrumb-item>文章管理</el-breadcrumb-item>
      <el-breadcrumb-item>写文章</el-breadcrumb-item>
    </el-breadcrumb>
    <el-card class="box-card">
      <div class="card-main">
        <div class="main-l">
          <el-input v-model="form.title" placeholder="请输入标题" class="title"></el-input>
          <quill-editor
            v-model="form.content"
            style="margin-bottom:66px;flex:1"
            ref="myQuillEditor"
            :options="editorOption"
          ></quill-editor>
        </div>
        <div class="main-r">
          <div class="btns">
            <el-button type="primary" @click="handlePublish">发布文章</el-button>
            <el-button type="success">保存草稿</el-button>
          </div>
          <el-form ref="form" :model="form" label-width="80px">
            <el-form-item label="是否公开" required>
              <el-radio v-model="form.public" :label="1">公开</el-radio>
              <el-radio v-model="form.public" :label="0">私密</el-radio>
            </el-form-item>
            <el-form-item label="文章分类" required>
              <el-select v-model="form.category" placeholder="请选择文章分类">
                <el-option
                  :label="item.cgname"
                  :value="item.cgid"
                  v-for="item in categories"
                  :key="item._id"
                ></el-option>
              </el-select>
            </el-form-item>

            <el-form-item label="文章封面">
              <el-upload
                class="upload-demo"
                :action="url+'/upload/cover'"
                list-type="picture"
                name="cover"
                :file-list="coverList"
                :multiple="false"
                :limit="1"
                :on-success="handleCoverUpload"
              >
                <el-button size="small" type="primary">点击上传</el-button>
                <div slot="tip" class="el-upload__tip">只能上传jpg/png文件，且不超过500kb</div>
              </el-upload>
            </el-form-item>
            <el-form-item label="文章标签">
              <el-tag
                :key="tag"
                v-for="tag in dynamicTags"
                closable
                :disable-transitions="false"
                @close="handleClose(tag)"
              >{{tag}}</el-tag>
              <el-input
                class="input-new-tag"
                v-if="inputVisible"
                v-model="inputValue"
                ref="saveTagInput"
                size="small"
                @keyup.enter.native="handleInputConfirm"
                @blur="handleInputConfirm"
              ></el-input>
              <el-button v-else class="button-new-tag" size="small" @click="showInput">+ 新标签</el-button>
            </el-form-item>
            <el-form-item label="发布日期" required>
              <el-date-picker
                v-model="form.publishDate"
                type="datetime"
                placeholder="选择发布日期"
                align="right"
                :picker-options="pickerOptions"
              ></el-date-picker>
            </el-form-item>
            <el-form-item label="是否原创" required>
              <el-radio v-model="form.original" :label="1">原创</el-radio>
              <el-radio v-model="form.original" :label="0">转载</el-radio>
            </el-form-item>
            <el-form-item label="开启评论" required>
              <el-radio v-model="form.openCmt" :label="1">是</el-radio>
              <el-radio v-model="form.openCmt" :label="0">否</el-radio>
            </el-form-item>
            <el-form-item label="文章简介">
              <el-input type="textarea" v-model="form.intro" placeholder="文章简介" rows="3"></el-input>
            </el-form-item>
          </el-form>
        </div>
      </div>
    </el-card>
  </div>
</template>
<script>
import VueQuillEditor, { Quill } from "vue-quill-editor";
import ImageResize from "quill-image-resize-module";
import { container, ImageExtend, QuillWatch } from "quill-image-extend-module";
Quill.register("modules/imageResize", ImageResize);
Quill.register("modules/ImageExtend", ImageExtend);
export default {
  data() {
    return {
      editMode: false,
      id: null,
      url: "",
      coverList: [],
      editorOption: {
        placeholder: "请在这里输入",
        modules: {
          imageResize: {},
          ImageExtend: {
            loading: true,
            name: "img",
            action: this.$serveUrl + "/upload/img",
            response: res => {
              return this.$serveUrl + res.data.url;
            }
          },
          toolbar: {
            container: container,
            handlers: {
              image: function() {
                // 劫持原来的图片点击按钮事件
                QuillWatch.emit(this.quill.id);
              }
            }
          }
        }
      },
      pickerOptions: {
        shortcuts: [
          {
            text: "今天",
            onClick(picker) {
              picker.$emit("pick", new Date());
            }
          },
          {
            text: "昨天",
            onClick(picker) {
              const date = new Date();
              date.setTime(date.getTime() - 3600 * 1000 * 24);
              picker.$emit("pick", date);
            }
          },
          {
            text: "明天",
            onClick(picker) {
              const date = new Date();
              date.setTime(date.getTime() + 3600 * 1000 * 24);
              picker.$emit("pick", date);
            }
          }
        ]
      },
      form: {
        content: "",
        title: "",
        original: 1,
        category: 1,
        openCmt: 1,
        cover: "",
        intro: "",
        tags: "",
        publishDate: null,
        public: 1
      },
      categories: [],
      dynamicTags: [],
      inputVisible: false,
      inputValue: ""
    };
  },
  created() {
    this.$myLoading();
    this.url = this.$serveUrl;
    if (this.$route.query.id) {
      this.editMode = true;
      this.id = this.$route.query.id;
      this.getArticleInfo();
    }
    this.getCategories();
  },
  mounted() {
    //中文提示
    const { addQuillTitle } = require("../assets/quill-title.js");
    addQuillTitle();
  },
  methods: {
    async handlePublish() {
      let tags = this.dynamicTags.join(";");
      this.form.tags = tags;
      if (!this.form.title || !this.form.content)
        return this.$message.error("请填写必填项");

      if (this.editMode) {
        //修改模式
        let res = await this.$http.put("/articles/" + this.id, this.form);
        if (res.meta.status != 200) return this.$message.error(res.meta.msg);
        this.$message.success("修改成功");
      } else {
        //发布模式
        let res = await this.$http.post("/articles", this.form);
        if (res.meta.status != 200) return this.$message.error(res.meta.msg);
        this.$message.success("发布成功");
      }
    },
    async getArticleInfo() {
      let result = await this.$http.get("/articles/" + this.id);
      if (result.meta.status != 200)
        return this.$message.error(result.meta.msg);
      this.form = result.data;
      this.dynamicTags =
        (result.data.tags && result.data.tags.split(";")) || [];
      this.coverList = [];
      this.coverList.push({ name: "封面", url: this.url + result.data.cover });
    },
    async getCategories() {
      let res = await this.$http.get("/categories/list");
      this.categories = res.data;
    },
    handleCoverUpload(res, file, fileList) {
      let url = res.data.url;
      this.form.cover = url;
    },
    handleClose(tag) {
      this.dynamicTags.splice(this.dynamicTags.indexOf(tag), 1);
    },
    showInput() {
      this.inputVisible = true;
      this.$nextTick(_ => {
        this.$refs.saveTagInput.$refs.input.focus();
      });
    },

    handleInputConfirm() {
      let inputValue = this.inputValue;
      if (inputValue) {
        this.dynamicTags.push(inputValue);
      }
      this.inputVisible = false;
      this.inputValue = "";
    }
  }
};
</script>
<style  scoped>
.el-form {
  margin: 0 auto;
}
.title {
  margin-bottom: 10px;
}
.card-main {
  display: flex;
  justify-content: space-between;
  height: 760px;
  align-items: stretch;
}
.main-l {
  width: 55%;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}
.main-r {
  width: 43%;
  border: 1px solid #ccc;
  padding: 15px;
}
.search {
  width: 500px;
}
.el-dialog .el-form-item:last-child {
  margin-left: 80px;
}
.btns {
  margin-bottom: 15px;
}
.el-tag + .el-tag {
  margin-left: 10px;
}
.button-new-tag {
  height: 32px;
  line-height: 30px;
  padding-top: 0;
  padding-bottom: 0;
}
.input-new-tag {
  width: 90px;
  margin-left: 10px;
  vertical-align: bottom;
}
.el-tag {
  margin-right: 10px;
}
</style>